#!/bin/bash
# ╔══════════════════════════════════════════════════════════════════╗
# ║         FlatDesign Theme — Pterodactyl Installer                ║
# ║                     by fidzzcodex                               ║
# ║                                                                 ║
# ║  Standalone — semua file tema sudah embedded di script ini      ║
# ║  One-liner: curl -sSL <url> | sudo bash                         ║
# ╚══════════════════════════════════════════════════════════════════╝

set -e

# ── Colors ────────────────────────────────────────────────────────
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
CYAN='\033[0;36m'
BOLD='\033[1m'
DIM='\033[2m'
RESET='\033[0m'

# ── Config ────────────────────────────────────────────────────────
PANEL_DIR="/var/www/pterodactyl"
THEME_NAME="flatdesign"
TEMP_DIR="/tmp/fd-theme-$$"

# ── Embedded Files (base64) ───────────────────────────────────────
CONF_B64=""
CSS_B64=""
JS_B64=""

# ── Helpers ───────────────────────────────────────────────────────
info()    { echo -e "${CYAN}  [*]${RESET} $1"; }
success() { echo -e "${GREEN}  [✓]${RESET} $1"; }
warn()    { echo -e "${YELLOW}  [!]${RESET} $1"; }
error()   { echo -e "${RED}  [✗]${RESET} $1"; exit 1; }
step()    { echo -e "\n${BOLD}${BLUE}  ── $1${RESET}"; }
divider() { echo -e "${DIM}  ────────────────────────────────────────${RESET}"; }

cleanup() { rm -rf "$TEMP_DIR"; }
trap cleanup EXIT

# ── Banner ────────────────────────────────────────────────────────
banner() {
  clear 2>/dev/null || true
  echo ""
  echo -e "${BLUE}${BOLD}"
  echo "   ███████╗██╗      █████╗ ████████╗"
  echo "   ██╔════╝██║     ██╔══██╗╚══██╔══╝"
  echo "   █████╗  ██║     ███████║   ██║   "
  echo "   ██╔══╝  ██║     ██╔══██║   ██║   "
  echo "   ██║     ███████╗██║  ██║   ██║   "
  echo "   ╚═╝     ╚══════╝╚═╝  ╚═╝   ╚═╝   "
  echo -e "${RESET}"
  echo -e "   ${BOLD}FlatDesign Theme — Pterodactyl${RESET}"
  echo -e "   ${DIM}by fidzzcodex · fidzzcodex.me${RESET}"
  echo ""
  divider
  echo ""
}

# ── Root check ────────────────────────────────────────────────────
check_root() {
  if [[ "$EUID" -ne 0 ]]; then
    error "Script ini harus dijalankan sebagai root."
    echo -e "  Gunakan: ${BOLD}sudo bash install.sh${RESET}"
    exit 1
  fi
}

# ── Detect panel ──────────────────────────────────────────────────
detect_panel() {
  step "Deteksi Panel Pterodactyl"

  if [[ ! -d "$PANEL_DIR" ]]; then
    warn "Panel tidak ditemukan di $PANEL_DIR"
    echo -ne "  ${CYAN}Masukkan path panel: ${RESET}"
    read -r PANEL_DIR
    [[ ! -d "$PANEL_DIR" ]] && error "Directory $PANEL_DIR tidak ditemukan."
  fi

  [[ ! -f "$PANEL_DIR/artisan" ]] && error "Bukan direktori Pterodactyl yang valid."

  success "Panel ditemukan: $PANEL_DIR"
}

# ── Check / Install Blueprint ─────────────────────────────────────
check_blueprint() {
  step "Cek Blueprint"

  if command -v blueprint &>/dev/null; then
    success "Blueprint sudah terinstall"
    return 0
  fi

  warn "Blueprint belum terinstall. Menginstall sekarang..."
  command -v curl &>/dev/null || apt-get install -y curl -qq
  command -v zip  &>/dev/null || apt-get install -y zip -qq

  cd "$PANEL_DIR"
  curl -sSL https://blueprint.zip/install.sh | bash

  command -v blueprint &>/dev/null || error "Blueprint gagal terinstall."
  success "Blueprint berhasil terinstall!"
}

# ── Extract embedded files ────────────────────────────────────────
extract_files() {
  step "Ekstrak File Tema"

  command -v zip &>/dev/null || apt-get install -y zip -qq

  mkdir -p "$TEMP_DIR/css" "$TEMP_DIR/js"
  echo "$CONF_B64" | base64 -d > "$TEMP_DIR/conf.yml"
  echo "$CSS_B64"  | base64 -d > "$TEMP_DIR/css/flatdesign.css"
  echo "$JS_B64"   | base64 -d > "$TEMP_DIR/js/flatdesign.js"

  success "File tema siap"
}

# ── Install theme ─────────────────────────────────────────────────
do_install() {
  step "Build & Install Tema"

  cd "$TEMP_DIR"
  zip -r "${THEME_NAME}.blueprint" conf.yml css/ js/ &>/dev/null

  cp "${THEME_NAME}.blueprint" "$PANEL_DIR/"
  cd "$PANEL_DIR"

  info "Menjalankan blueprint install..."
  blueprint install "${THEME_NAME}.blueprint"
  rm -f "$PANEL_DIR/${THEME_NAME}.blueprint"

  success "Tema berhasil diinstall!"
}

# ── Uninstall theme ───────────────────────────────────────────────
do_uninstall() {
  step "Uninstall Tema"

  command -v blueprint &>/dev/null || error "Blueprint tidak ditemukan."

  # Cek apakah tema terinstall
  if ! blueprint list 2>/dev/null | grep -q "$THEME_NAME"; then
    warn "Tema '$THEME_NAME' sepertinya belum terinstall."
    echo -ne "  Tetap lanjutkan uninstall? (y/N): "
    read -r force
    [[ "$force" != "y" && "$force" != "Y" ]] && { info "Dibatalkan."; return; }
  fi

  cd "$PANEL_DIR"
  blueprint remove "$THEME_NAME"
  success "Tema berhasil dihapus!"
}

# ── Clear cache ───────────────────────────────────────────────────
clear_cache() {
  step "Clear Cache Panel"
  cd "$PANEL_DIR"

  php artisan view:clear   &>/dev/null && success "View cache cleared"
  php artisan cache:clear  &>/dev/null && success "App cache cleared"
  php artisan config:clear &>/dev/null && success "Config cache cleared"

  chown -R www-data:www-data "$PANEL_DIR" 2>/dev/null ||   chown -R nginx:nginx       "$PANEL_DIR" 2>/dev/null || true
  success "Permissions fixed"
}

# ── Done install ──────────────────────────────────────────────────
done_install() {
  echo ""
  divider
  echo ""
  echo -e "  ${GREEN}${BOLD}Instalasi Selesai! ✓${RESET}"
  echo ""
  echo -e "  ${CYAN}Tema FlatDesign sudah aktif di panel.${RESET}"
  echo -e "  ${CYAN}Buka browser dan refresh halaman Pterodactyl.${RESET}"
  echo ""
  echo -e "  ${YELLOW}Toggle dark/light :${RESET}  tombol pojok kanan bawah"
  echo -e "  ${YELLOW}Admin panel       :${RESET}  tidak berubah"
  echo -e "  ${YELLOW}Console terminal  :${RESET}  tidak berubah"
  echo ""
  divider
  echo ""
}

# ── Done uninstall ────────────────────────────────────────────────
done_uninstall() {
  echo ""
  divider
  echo ""
  echo -e "  ${GREEN}${BOLD}Uninstall Selesai! ✓${RESET}"
  echo ""
  echo -e "  ${CYAN}Tema FlatDesign sudah dihapus dari panel.${RESET}"
  echo -e "  ${CYAN}Panel kembali ke tampilan default Pterodactyl.${RESET}"
  echo ""
  divider
  echo ""
}

# ── Interactive menu ──────────────────────────────────────────────
show_menu() {
  echo -e "  ${BOLD}Pilih aksi:${RESET}"
  echo ""
  echo -e "  ${GREEN}  1)${RESET}  Install Tema FlatDesign"
  echo -e "  ${RED}  2)${RESET}  Uninstall Tema FlatDesign"
  echo -e "  ${DIM}  3)${RESET}  Keluar"
  echo ""
  divider
  echo -ne "\n  ${BOLD}Masukkan pilihan [1-3]: ${RESET}"
  read -r choice

  case "$choice" in
    1)
      echo ""
      info "Memulai instalasi tema..."
      detect_panel
      check_blueprint
      extract_files
      do_install
      clear_cache
      done_install
      ;;
    2)
      echo ""
      warn "Kamu akan menghapus tema FlatDesign dari panel."
      echo -ne "  ${BOLD}Yakin? (y/N): ${RESET}"
      read -r confirm
      if [[ "$confirm" == "y" || "$confirm" == "Y" ]]; then
        detect_panel
        do_uninstall
        clear_cache
        done_uninstall
      else
        echo ""
        info "Dibatalkan."
        echo ""
      fi
      ;;
    3)
      echo ""
      info "Keluar."
      echo ""
      exit 0
      ;;
    *)
      echo ""
      warn "Pilihan tidak valid. Masukkan 1, 2, atau 3."
      echo ""
      show_menu
      ;;
  esac
}

# ── Main ──────────────────────────────────────────────────────────
main() {
  banner
  check_root

  # Kalau ada argument langsung, skip menu
  case "${1:-}" in
    install)
      detect_panel; check_blueprint; extract_files; do_install; clear_cache; done_install ;;
    uninstall|remove)
      detect_panel; do_uninstall; clear_cache; done_uninstall ;;
    cache)
      detect_panel; clear_cache; success "Cache cleared" ;;
    *)
      # Tampilkan menu interaktif
      show_menu
      ;;
  esac
}

main "$@"
